-- Part 1: University-level data for Lancaster University
UPDATE public.universities SET
  website_url = 'https://www.lancaster.ac.uk/',
  tuition_usd = 34620,
  overall_acceptance_rate = '18.69%',
  test_policy = 'Not applicable',
  deadline_calendar = 'UCAS equal consideration deadline: January 14 (18:00 UK time). Medicine (MBChB): October 15 (18:00 UK time). UCAS Extra available from late February for applicants with no offers. Clearing opens in July. International applicants encouraged to apply well before the deadline. Deferred entry accepted for most programmes.',
  financial_aid = 'Lancaster Global Scholarships: international undergraduate scholarships covering up to full tuition fees, awarded on academic merit. Vice-Chancellor Scholarship for international students. GREAT Scholarships available in partnership with the British Council for students from eligible countries. Country-specific bursaries (e.g. for students from India, China, South and Southeast Asia). Lancaster Management School scholarships for high-achieving business applicants. Lancaster Achievement Award for UK/EU students with financial need. UK government Tuition Fee Loans and Maintenance Loans available for home students. Santander Scholarships partnership. Full scholarship listings available at lancaster.ac.uk/study/fees-and-funding/scholarships-and-bursaries/.'
WHERE name = 'Lancaster University';

-- Part 2: Top 10 majors for Lancaster University
INSERT INTO public.majors (university_id, major_name, acceptance_rate, supplemental_requirements, subject_ranking, ielts_min, toefl_min, sat_min, act_min, gpa_min, a_level_grades, ib_min, atar_min, duolingo_min, pte_min)
